  void print (ostream& os) const {
	  os<<"Node name : ProcedureDeclaration. Proc name is: "<<*name_<<endl;
	  assert(block_);
	  if (formal_list_){
		  formal_list_->print(os);
	  }
	  block_->print(os);
  }

  Node * clone () const { return new ProcedureDeclaration(*this);}

public:
  Node * block_;
  Node * formal_list_;
  string * name_;
};

class DeclarationList : public Node {
